import{_ as s,c as a,o as n,O as p}from"./chunks/framework.97fbe135.js";const h=JSON.parse('{"title":"SpringBoot整合Alipay","description":"SpringBoot整合Alipay","frontmatter":{"title":"SpringBoot整合Alipay","description":"SpringBoot整合Alipay","date":"2022-05-22T00:00:00.000Z","category":"SpringBoot","tags":["alipay","支付"]},"headers":[],"relativePath":"posts/springboot-alipay.md","lastUpdated":1681706878000}'),l={name:"posts/springboot-alipay.md"},e=p(`<h1 id="springboot整合alipay" tabindex="-1">SpringBoot整合Alipay <a class="header-anchor" href="#springboot整合alipay" aria-label="Permalink to &quot;SpringBoot整合Alipay&quot;">​</a></h1><p>支付宝开放平台</p><p><a href="https://open.alipay.com/platform/home.htm?from=wwwalipay" target="_blank" rel="noreferrer">https://open.alipay.com/platform/home.htm?from=wwwalipay</a></p><p>开发助手</p><p><a href="https://opendocs.alipay.com/common/02kipl" target="_blank" rel="noreferrer">https://opendocs.alipay.com/common/02kipl</a></p><p>生成密钥 复制公钥</p><p>web 沙箱应用： 自定义密钥-&gt;公钥查看-&gt;加签变更-&gt;粘贴</p><p>springboot需要用到的配置</p><div class="language-yaml line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#676E95;font-style:italic;"># 应用ID,您的APPID web沙箱应用中获取</span></span>
<span class="line"><span style="color:#C3E88D;">appId:2021000119675024</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># 商户私钥，您的PKCS8格式RSA2私钥，通过开发助手生成的应用私钥</span></span>
<span class="line"><span style="color:#F07178;">privateKey</span><span style="color:#89DDFF;">:</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># 支付宝公钥,在沙箱应用获取，通过应用公钥生成支付宝公钥</span></span>
<span class="line"><span style="color:#F07178;">publicKey</span><span style="color:#89DDFF;">:</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># 服务器异步通知页面路径需http://格式的完整路径，不能加?id=123这类自定义参数</span></span>
<span class="line"><span style="color:#C3E88D;">notifyUrl:http://localhost:8081/alipay/success</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># 页面跳转同步通知页面路径 需http://格式的完整路径，不能加?id=123这类自定义参数</span></span>
<span class="line"><span style="color:#F07178;">returnUrl</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">http://localhost:8081/alipay/success</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># 签名方式</span></span>
<span class="line"><span style="color:#F07178;">signType</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">RSA2</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># 字符编码格式</span></span>
<span class="line"><span style="color:#F07178;">charset</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">utf-8</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># 支付宝网关，在沙箱应用中获取</span></span>
<span class="line"><span style="color:#F07178;">gatewayUrl</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">https://openapi.alipaydev.com/gateway.do</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br></div></div><h3 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h3><p><a href="https://blog.csdn.net/ybsgsg/article/details/124348842" target="_blank" rel="noreferrer">springboot实现支付宝支付功能</a></p>`,11),t=[e];function o(r,i,c,y,b,m){return n(),a("div",null,t)}const u=s(l,[["render",o]]);export{h as __pageData,u as default};
